const root = $input.first().json;
const body = root.body || root;
const data = body.data || body.message || body;
const raw = data.raw || {};
const rawMessage = raw.message || {};
const rawContact = Array.isArray(raw.contacts) ? raw.contacts[0] : {};
const headers = root.headers || {};

const stateManagerUrl = 'https://n8n.miqra.dev/webhook/conversation-state';

function firstValue(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim()) return value;
  }
  return '';
}

function onlyDigits(value) {
  return String(value || '').replace(/\D/g, '');
}

function normalizePhone(value) {
  const digits = onlyDigits(value);
  if (!digits) return '';
  if (digits.startsWith('0')) return `62${digits.slice(1)}`;
  return digits;
}

function normalizeText(value) {
  return String(value || '').replace(/\s+/g, ' ').trim();
}

function normalizeMessageType(value) {
  const type = String(value || '').toLowerCase();
  if (['image', 'template', 'button', 'audio', 'document', 'video'].includes(type)) return type;
  return 'text';
}

const eventType = String(firstValue(body.event_type, body.event, headers['x-kirimchat-event'])).toLowerCase();
const directionRaw = String(firstValue(data.direction, raw.direction, rawMessage.direction)).toLowerCase();
const messageType = normalizeMessageType(firstValue(data.message_type, data.type, rawMessage.type));
const buttonTitle = firstValue(data.button_reply?.title, rawMessage.interactive?.button_reply?.title);
const content = firstValue(data.content, data.text, rawMessage.text?.body, data.caption, rawMessage.image?.caption);
const plainText = normalizeText(buttonTitle || content);
const phone = normalizePhone(firstValue(
  data.customer_phone,
  data.customer?.phone,
  data.contact?.phone,
  data.phone,
  data.to,
  data.recipient,
  rawContact.wa_id,
  rawMessage.from,
));
const customerName = firstValue(data.customer_name, data.customer?.name, rawContact.profile?.name, 'Pelanggan');
const senderNumber = normalizePhone(firstValue(
  raw.metadata?.display_phone_number,
  data.sender_phone,
  data.from,
  rawMessage.from,
));

const isOutbound = directionRaw === 'outbound' ||
  eventType.includes('message.sent') ||
  eventType.includes('message.delivered') ||
  eventType.includes('message.outbound') ||
  eventType.includes('outbound');
const isInbound = directionRaw === 'inbound' ||
  eventType.includes('message.received') ||
  eventType.includes('message.inbound') ||
  eventType.includes('inbound');

async function handleManualOutbound() {
  if (!phone || !plainText) return;
  if (['system', 'notification', 'template'].includes(messageType)) return;

  const stateResp = await this.helpers.httpRequest({
    method: 'POST',
    url: stateManagerUrl,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ action: 'get_with_global', phone, messageLimit: 50 }),
    json: true,
  });

  const hasOrderState = Boolean(stateResp.order_id || stateResp.productName || stateResp.csName);
  const reportingEnabled = stateResp.reportingEnabled !== false;
  if (!reportingEnabled || !hasOrderState) return;

  const normalizedOutbound = normalizeText(plainText);
  const recentAiEcho = (stateResp.messages || []).slice(-12).some((message) => {
    const createdAt = Number(message.createdAt || 0);
    const recent = !createdAt || createdAt > Date.now() - (15 * 60 * 1000);
    return recent &&
      message.role === 'ai' &&
      message.direction === 'outbound' &&
      normalizeText(message.content) === normalizedOutbound;
  });

  if (recentAiEcho) return;

  await this.helpers.httpRequest({
    method: 'POST',
    url: stateManagerUrl,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      action: 'append_message',
      phone,
      order_id: stateResp.order_id || '',
      role: 'cs',
      direction: 'outbound',
      content: plainText,
      messageType,
    }),
    json: true,
  });


  if (normalizedOutbound.includes('PEMESANAN BERHASIL')) {
    const sourceMessageText = String(buttonTitle || content || plainText || '');
    await this.helpers.httpRequest({
      method: 'POST',
      url: stateManagerUrl,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        action: 'upsert_shipping_recap',
        phone,
        order_id: stateResp.order_id || '',
        customerName: stateResp.customerName || customerName || '',
        csName: stateResp.csName || 'CS Aisyah',
        csNumber: stateResp.csNumber || senderNumber || '',
        sourceMessageId: firstValue(data.message_id, data.id, rawMessage.id),
        sourceMessageText,
        closedAt: Date.now(),
      }),
      json: true,
    });
  }
  await this.helpers.httpRequest({
    method: 'POST',
    url: stateManagerUrl,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      action: 'set',
      phone,
      order_id: stateResp.order_id || '',
      status: 'handover',
      note: 'manual CS replied',
      customerName,
      csNumber: senderNumber,
    }),
    json: true,
  });
}

if (isOutbound) {
  await handleManualOutbound.call(this);
  return [];
}

if (!isInbound) return [];


const fileHandoverTypes = ['document', 'audio', 'video'];
if (fileHandoverTypes.includes(messageType)) {
  if (!phone) return [];
  const fileUrl = firstValue(data.media_url, data.document_url, data.file_url, data.url, rawMessage.document?.url, rawMessage.audio?.url, rawMessage.video?.url);
  const caption = normalizeText(content);
  const label = messageType === 'document' ? 'dokumen/PDF' : messageType;
  const messageText = caption
    ? `[Customer mengirim ${label}]\nKeterangan: ${caption}\nURL: ${fileUrl}`
    : `[Customer mengirim ${label} tanpa keterangan]\nURL: ${fileUrl}`;
  return [{ json: { phone, messageText, messageType, fileUrl, customerName, senderNumber, rawPayload: body } }];
}
if (messageType === 'image') {
  if (!phone) return [];
  const imageUrl = firstValue(data.media_url, data.image_url, data.url, rawMessage.image?.url);
  const caption = normalizeText(content);
  const messageText = caption
    ? `[Customer mengirim gambar]\nKeterangan: ${caption}\nURL: ${imageUrl}`
    : `[Customer mengirim gambar tanpa keterangan]\nURL: ${imageUrl}`;
  return [{ json: { phone, messageText, messageType: 'image', imageUrl, customerName, senderNumber, rawPayload: body } }];
}

if (!phone || !plainText) return [];
if (['system', 'notification', 'template'].includes(messageType)) return [];

return [{ json: { phone, messageText: plainText, messageType, customerName, senderNumber, rawPayload: body } }];

let aiOutput = ($input.first().json.output || '').trim();
const inbound = $('02 Parse Message + Manual CS Guard').item.json;
const phone = inbound.phone;
const parseState = $('04 Validate AI Scope + State').item.json;
const inboundText = String(inbound.messageText || '').toLowerCase();
const inboundLooksLikeTemplateButtonReply = /assalamu?a?['']?alaikum[\s\S]{0,900}(?:transfer aja|cod\s*(?:\(|aja|ya)|bayar di tempat)/i.test(inbound.messageText || '') || /.\s*(?:transfer aja|cod)/i.test(inbound.messageText || '');
const latestCustomerActuallySaidSalam = /\b(?:assalamu?a?['']?alaikum|assalamualaikum|salam|halo|hai|pagi|siang|sore|malam)\b/i.test(inbound.messageText || '') && !inboundLooksLikeTemplateButtonReply;
const isInvoiceOrderGreeting = /assalamu?a?['']?alaikum/i.test(inbound.messageText || '') && /saya\s+mau\s+pesan|pustakaislam\.net\/o\//i.test(inbound.messageText || '') && !/.\s*(?:transfer aja|cod)/i.test(inbound.messageText || '');
const inboundMessageType = inbound.messageType || 'text';
const isImageInbound = inboundMessageType === 'image';
const fileNeedsHandover = ['document', 'audio', 'video'].includes(inboundMessageType);
const transferClaimTerms = [
  'sudah transfer', 'udah transfer', 'sdh transfer', 'telah transfer', 'baru transfer', 'barusan transfer', 'habis transfer',
  'sudah saya transfer', 'saya sudah transfer', 'saya transfer', 'aku transfer',
  'sudah tf', 'udah tf', 'sdh tf', 'telah tf', 'saya tf',
  'sudah bayar', 'udah bayar', 'sdh bayar', 'telah bayar', 'sudah dibayar', 'saya bayar',
  'ini bukti', 'bukti transfer', 'bukti tf', 'struk transfer', 'receipt transfer'
];
const hasTransferClaim = transferClaimTerms.some((term) => inboundText.includes(term));
const claimedTransferClosing = aiOutput.includes('PEMESANAN BERHASIL') && aiOutput.includes('ORDER TRANSFER');

if (isInvoiceOrderGreeting && !aiOutput.includes('PEMESANAN BERHASIL')) {
  aiOutput = `Wa A'laikumussalam Warahmatullahi Wabarakatuh
Alhamdulillah data pesanan sudah masuk ya Kak ??

Boleh info Kak mau COD atau Transfer ya?`;
}

function parseRupiahToNumber(value) {
  const digits = String(value || '').replace(/[^0-9]/g, '');
  return digits ? Number(digits) : 0;
}

function pickMediaUrl() {
  const textUrl = String(inbound.messageText || '').match(/https?:\/\/\S+/i)?.[0] || '';
  return inbound.imageUrl || inbound.fileUrl || textUrl;
}

async function verifyPaymentProofImage(mediaUrl) {
  if (!mediaUrl) {
    return { verified: false, reason: 'no media url' };
  }

  const expectedTotal = parseState.total || '';
  const expectedAmount = parseRupiahToNumber(expectedTotal);
  const verifierPrompt = `
You verify Indonesian bank transfer proof images for PustakaIslam.
Return ONLY JSON. No markdown.

Expected recipient account owner must match one of:
- Rahmany Amanda M
- Rahmany Amanda Meyri
- Rahmany Amanda Meyriza

Expected account numbers may be one of:
- BCA 4660245877
- BSI 7353424623
- Mandiri 1560027353426

Expected order total: ${expectedTotal} (${expectedAmount}).

Set verified=true ONLY if the image is clearly a bank/e-wallet transfer receipt AND:
1. recipient name or account number matches the expected recipient/accounts, AND
2. transferred amount is visible and equals the expected total, allowing only formatting differences like Rp, dots, commas.

If the image is product/bonus/photo/chat screenshot/not a receipt, verified=false.
If amount or recipient is unclear, verified=false.

JSON schema:
{
  "is_payment_proof": boolean,
  "verified": boolean,
  "recipient_match": boolean,
  "amount_match": boolean,
  "recipient_text": string,
  "account_text": string,
  "amount_text": string,
  "bank_text": string,
  "confidence": "high" | "medium" | "low",
  "reason": string
}`.trim();

  try {
    const response = await this.helpers.httpRequestWithAuthentication.call(this, 'openAiApi', {
      method: 'POST',
      url: 'https://api.openai.com/v1/chat/completions',
      headers: { 'Content-Type': 'application/json' },
      body: {
        model: 'gpt-5-mini',
        messages: [{
          role: 'user',
          content: [
            { type: 'text', text: verifierPrompt },
            { type: 'image_url', image_url: { url: mediaUrl, detail: 'high' } },
          ],
        }],
        response_format: { type: 'json_object' },
        max_completion_tokens: 350,
        reasoning_effort: 'minimal',
      },
      json: true,
    });
    const content = response.choices?.[0]?.message?.content || '{}';
    const parsed = JSON.parse(content);
    return { ...parsed, raw: parsed };
  } catch (error) {
    return { verified: false, reason: `vision verifier error: ${error.message || error}` };
  }
}

function buildTransferClosing() {
  return `Alhamdulillah, bukti transfer sudah kami terima Kak ??

*PEMESANAN BERHASIL*
\`ORDER TRANSFER\`

Detail pesanan:
Produk: *${parseState.products || parseState.productName || ''}*
Harga: *${parseState.productsSubtotal || ''}*
Ongkir: ${parseState.shippingCost || ''}
*Total: ${parseState.total || ''}*

?? Dikirim ke:
${parseState.customerName || inbound.customerName || 'Kak'} | ${phone}
${parseState.shippingAddress || ''}, ${parseState.shippingDistrict || ''}, ${parseState.shippingCity || ''}

Semoga lancar rezeki dan sehat selalu,
Baarakallahu fiik ??`;
}

if (isImageInbound || fileNeedsHandover) {
  const recentTransferContext = (parseState.messages || []).slice(-8).some((message) => /4660245877|7353424623|1560027353426|rekening|transfer|tf|bukti|bayar/i.test(String(message.content || '')));
  const explicitPaymentProofText = /bukti|transfer|tf|bayar|struk|receipt|resi transfer|sudah transfer|udah tf/i.test(inboundText);
  const imageLooksProductRelated = /bonus|gambar|foto|ini\?|ini ya|contoh|cover|halaman|produk/i.test(inboundText);
  const shouldVerifyPaymentProof = isImageInbound && (explicitPaymentProofText || (recentTransferContext && !imageLooksProductRelated));

  if (shouldVerifyPaymentProof) {
    const verification = await verifyPaymentProofImage.call(this, pickMediaUrl());
    const verified = verification.verified === true && verification.is_payment_proof === true && verification.recipient_match === true && verification.amount_match === true;
    aiOutput = verified
      ? buildTransferClosing()
      : `[HANDOVER] bukti transfer perlu dicek manual (${verification.reason || 'uncertain'})\nTerima kasih buktinya Kak ?? Sebentar kami cek dulu ke bagian keuangan ya`;
  } else {
    aiOutput = `[HANDOVER] gambar/file perlu dicek\nBaik Kak ?? Sebentar ya`;
  }
} else if (claimedTransferClosing && hasTransferClaim) {
  aiOutput = `Baik Kak, mohon kirim bukti transfernya ya ??\nAgar pesanan bisa langsung kami proses.`;
}

const photoOrDiscountNeedsHandover = /(foto|fotonya|gambar|gambarnya|cover|halaman contoh|bentuk fisik|foto real|ongkir.*mahal|ongkir.*murah|ongkir gratis|free ongkir|diskon ongkir|potongan ongkir|kurangin ongkir|bisa kurang|harga.*kurang|diskon|nego)/i.test(inboundText);
if (!aiOutput.startsWith('[HANDOVER]') && !aiOutput.includes('PEMESANAN BERHASIL') && photoOrDiscountNeedsHandover) {
  const discountIntent = /(ongkir.*mahal|ongkir.*murah|ongkir gratis|free ongkir|diskon ongkir|potongan ongkir|kurangin ongkir|bisa kurang|harga.*kurang|diskon|nego)/i.test(inboundText);
  const reason = discountIntent ? 'customer minta diskon/ongkir murah' : 'customer minta foto produk';
  aiOutput = `[HANDOVER] ${reason}\nBaik Kak ?? Sebentar ya`;
}

const customerDefersOrNeedsFollowup = /(diskusi(?:kan)?\\s+dulu|kami\\s+diskusi|saya\\s+diskusi|tanya\\s+(?:suami|istri|keluarga)\\s+dulu|nanti\\s+aja|nnti\\s+aja|ntar\\s+aja|pikir(?:-pikir)?\\s+dulu|dipikir\\s+dulu|belum\\s+dulu|jangan\\s+dulu)/i.test(inboundText);
if (!aiOutput.startsWith('[HANDOVER]') && !aiOutput.includes('PEMESANAN BERHASIL') && customerDefersOrNeedsFollowup) {
  aiOutput = '[HANDOVER] customer menunda/perlu follow up CS\\nBaik Kak, ditunggu kabar baiknya ya ??';
}

const pressureTransferFollowup = /kira-kira\s+mau\s+transfer\s+kapan|mau\s+transfer\s+kapan|kapan\s+transfer|besok\s+pagi\s+atau\s+siang/i;
if (!aiOutput.startsWith('[HANDOVER]') && !aiOutput.includes('PEMESANAN BERHASIL') && pressureTransferFollowup.test(aiOutput)) {
  aiOutput = 'Baik Kak, ditunggu bukti transfernya ya ??';
}

function normalizeShortReplyEmoji(text) {
  let value = String(text || '').trim();

  const PRAY = String.fromCodePoint(0x1F64F);
  const SMILE = String.fromCodePoint(0x1F60A);
  const LOVE = String.fromCodePoint(0x1F970);
  const HANDSHAKE = String.fromCodePoint(0x1F91D);
  const broken = '[\\uFFFD?]';
  const closingEmoji = `(?:${PRAY}|${SMILE}|${LOVE}|${HANDSHAKE})`;

  value = value.replace(/\uFFFD/g, PRAY);
  value = value.replace(new RegExp(`(Siap Kak[^\\n?.!]{0,80})\\s+${broken}\\s+(COD ya\\.?)`, 'gi'), `$1 ${SMILE} $2`);
  value = value.replace(new RegExp(`(Waalaikumussalam Kak|Walaikumussalam Kak|Halo Kak|Hai Kak)\\s+${broken}`, 'gi'), `$1 ${SMILE}`);
  value = value.replace(new RegExp(`(Terima kasih buktinya Kak)\\s+${broken}`, 'gi'), `$1 ${PRAY}`);
  value = value.replace(new RegExp(`(Baik Kak)\\s+${broken}\\s+(Sebentar ya)`, 'gi'), `$1 ${PRAY} $2`);
  value = value.replace(new RegExp(`(Biar paket segera kami proses ya Kak)\\s*(?:${PRAY}|${broken})+`, 'giu'), `$1 ${PRAY}`);
  value = value.replace(new RegExp(`(Baarakallahu fiik|Barakallahu fiik)\\s+${broken}`, 'gi'), `$1 ${PRAY}`);
  value = value.replace(new RegExp(`(Aaamiin|Aamiin|Sama-sama ya Kak|Sama-sama Kak)\\s+${broken}`, 'gi'), `$1 ${PRAY}`);
  value = value.replace(new RegExp(`Kak\\s+${broken}(?=\\s*(?:\\n|$))`, 'gi'), `Kak ${PRAY}`);

  const compact = value.replace(/\s+/g, ' ');
  if (compact.length > 90 || compact.includes('*PEMESANAN BERHASIL*')) {
    value = value.replace(new RegExp(`Biar paket (?:langsung|segera) kami proses ya Kak\\s*(?:${PRAY}|${broken})+`, 'giu'), `Biar paket segera kami proses ya Kak ${PRAY}`);
  }

  value = value.replace(new RegExp(`Baik Kak\\s+(?:${PRAY}|${broken})\\s+Sebentar ya`, 'iu'), `Baik Kak ${PRAY} Sebentar ya`);
  value = value.replace(new RegExp(`Aaamiin\\s*(?:${closingEmoji}\\s*)*`, 'iu'), `Aaamiin ${PRAY}`);
  value = value.replace(new RegExp(`Sama-sama ya Kak\\s*(?:${closingEmoji}\\s*)+`, 'iu'), `Sama-sama ya Kak ${PRAY}`);
  value = value.replace(new RegExp(`Sama-sama Kak\\s*(?:${closingEmoji}\\s*)+`, 'iu'), `Sama-sama Kak ${PRAY}`);
  value = value.replace(new RegExp(`Berkah selalu ya Kak\\s*(?:${closingEmoji}\\s*)+`, 'iu'), `Berkah selalu ya Kak ${SMILE}`);
  value = value.replace(new RegExp(`Baarakallahu fiik ya Kak\\s*${PRAY}\\s*Semoga berkah\\s*${SMILE}`, 'iu'), `Baarakallahu fiik ya Kak ${PRAY}`);
  value = value.replace(new RegExp(`(${closingEmoji})(?:\\s*${closingEmoji})+`, 'gu'), '$1');

  return value.trim();
}

function normalizeProfessionalTone(text) {
  let value = String(text || '');
  value = value.replace(/\\b(?:wkwk+|wk+w+k+|haha+|hehe+|hihi+|lol|lmao)\\b[,.! \\t]*/gi, '');
  value = value.replace(/[ \\t]{2,}/g, ' ');
  value = value.replace(/\n{3,}/g, '\n\n');
  return value.trim();
}
function normalizeCodConfirmationBold(text) {
  let value = String(text || '');
  if (value.includes('COD ya') && value.includes('Kami kirimkan ke')) {
    value = value.replace(/alamatnya\s+sudah (?:benar|sesuai)/gi, 'alamatnya *sudah sesuai*');
    value = value.replace(/mohon\s+balas:/gi, 'balas:');
    value = value.replace(/balas:\s*(?:Benar|Ya)/gi, 'balas:\n*Ya*');
    value = value.replace(/\*\*sudah (?:benar|sesuai)\*\*/gi, '*sudah sesuai*');
    value = value.replace(/\*\*(?:Benar|Ya)\*\*/gi, '*Ya*');
  }
  value = value.replace(/Biar paket (?:langsung|segera) kami proses ya Kak(?:\\s*(?:\\uFFFD|[?]|??)+)?/giu, 'Biar paket segera kami proses ya Kak ??');
  return value;
}

aiOutput = normalizeProfessionalTone(normalizeCodConfirmationBold(normalizeShortReplyEmoji(aiOutput)));
if (isCodTemplateClick && /^\\s*(?:waalaikumussalam|walaikumussalam|wa'alaikumussalam|waalaikumsalam)\\s+Kak/i.test(aiOutput)) {
  aiOutput = aiOutput.replace(/^\\s*(?:waalaikumussalam|walaikumussalam|wa'alaikumussalam|waalaikumsalam)\\s+Kak\\s*[?????]*\\s*\\n+/i, '');
}

const isCodTemplateClick = /(?:^|[.\n\r])\s*COD\s*(?:\(Bayar di Tempat\)|aja|ya)?\s*$/i.test(inbound.messageText || '') || /.\s*COD\s*\(Bayar di Tempat\)/i.test(inbound.messageText || '');
const recentAiCodStep1 = (parseState.messages || []).slice(-6).some((message) => {
  const createdAt = Number(message.createdAt || 0);
  const recent = !createdAt || createdAt > Date.now() - (5 * 60 * 1000);
  const content = String(message.content || '');
  return recent && message.role === 'ai' && /COD ya/i.test(content) && /Kalau alamatnya \*?sudah sesuai\*?/i.test(content);
});
if (isCodTemplateClick && recentAiCodStep1 && /COD ya/i.test(aiOutput) && /Kalau alamatnya \*?sudah sesuai\*?/i.test(aiOutput)) {
  return [];
}
if (!latestCustomerActuallySaidSalam) {
  aiOutput = aiOutput.replace(/^\s*(?:waalaikumussalam|walaikumussalam|wa'alaikumussalam|waalaikumsalam)\s+Kak\s*[?????]*\s*\n+/i, '');
  aiOutput = aiOutput.replace(/^\s*(?:halo|hai)\s+Kak\s*[?????]*\s*\n+/i, '');
}

const compactOutput = aiOutput.replace(/\s+/g, ' ').trim();
const defaultHandoverReply = /^baik kak(?:\s+[^\s,!.?]+)?[,!]?\s*(?:??|?|\?)?\s*sebentar ya\.?$/i.test(compactOutput) ||
  /^sebentar ya\.?$/i.test(compactOutput);
let isHandover = aiOutput.startsWith('[HANDOVER]') || defaultHandoverReply;

let handoverReason = '';
let replyText = aiOutput;
let isClosing = false;
let orderMethod = '';

if (isHandover) {
  if (defaultHandoverReply && !aiOutput.startsWith('[HANDOVER]')) {
    handoverReason = 'needs CS follow up';
    replyText = normalizeShortReplyEmoji(aiOutput);
  } else {
    const withoutTag = aiOutput.replace('[HANDOVER]', '').trim();
    const lines = withoutTag.split('\n');
    handoverReason = lines[0].trim();
    replyText = lines.slice(1).join('\n').trim() || 'Baik Kak ?? Sebentar ya';
  }
} else if (aiOutput.includes('PEMESANAN BERHASIL')) {
  isClosing = true;
  if (aiOutput.includes('ORDER COD')) {
    orderMethod = 'COD';
  } else if (aiOutput.includes('ORDER TRANSFER')) {
    orderMethod = 'Transfer';
  }
}

replyText = normalizeProfessionalTone(normalizeCodConfirmationBold(normalizeShortReplyEmoji(replyText)));
aiOutput = isHandover && !aiOutput.startsWith('[HANDOVER]')
  ? `[HANDOVER] ${handoverReason}\n${replyText}`
  : normalizeProfessionalTone(normalizeCodConfirmationBold(normalizeShortReplyEmoji(aiOutput)));


const historyHasClosingForPaymentGuard = (parseState.messages || []).some((message) => String(message.content || '').includes('PEMESANAN BERHASIL'));
const postClosingPaymentCta = /transfer\s+atau\s+cod|via\s+transfer\s+atau\s+cod|mau\s+lanjut\s+transfer|biar\s+langsung\s+kami\s+proses|sisihkan\s+dulu\s+paketnya/i.test(replyText + '\n' + aiOutput);
if (!isHandover && historyHasClosingForPaymentGuard && postClosingPaymentCta) {
  isClosing = false;
  orderMethod = '';
  replyText = 'Baarakallahu fiik ya Kak ??';
  aiOutput = replyText;
}
let bonusItem = '';
let instruksiPengiriman = '';
if (isClosing) {
  const bonusMatch = aiOutput.match(/^Bonus:\s*(.+)$/m);
  if (bonusMatch && bonusMatch[1] && !bonusMatch[1].includes('[')) {
    bonusItem = bonusMatch[1].trim();
  }
  const instruksiMatch = aiOutput.match(/^Instruksi:\s*(.+)$/m);
  if (instruksiMatch && instruksiMatch[1] && !instruksiMatch[1].includes('[')) {
    instruksiPengiriman = instruksiMatch[1].trim();
  }
