function normalizeShortReplyEmoji(text) {
  let value = String(text || '').trim();

  const PRAY = String.fromCodePoint(0x1F64F);
  const SMILE = String.fromCodePoint(0x1F60A);
  const LOVE = String.fromCodePoint(0x1F970);
  const HANDSHAKE = String.fromCodePoint(0x1F91D);
  const broken = '[\\uFFFD?]';
  const closingEmoji = `(?:${PRAY}|${SMILE}|${LOVE}|${HANDSHAKE})`;

  value = value.replace(/\uFFFD/g, PRAY);
  value = value.replace(new RegExp(`(Siap Kak[^\\n?.!]{0,80})\\s+${broken}\\s+(COD ya\\.?)`, 'gi'), `$1 ${SMILE} $2`);
  value = value.replace(new RegExp(`(Waalaikumussalam Kak|Walaikumussalam Kak|Halo Kak|Hai Kak)\\s+${broken}`, 'gi'), `$1 ${SMILE}`);
  value = value.replace(new RegExp(`(Terima kasih buktinya Kak)\\s+${broken}`, 'gi'), `$1 ${PRAY}`);
  value = value.replace(new RegExp(`(Baik Kak)\\s+${broken}\\s+(Sebentar ya)`, 'gi'), `$1 ${PRAY} $2`);
  value = value.replace(new RegExp(`(Biar paket segera kami proses ya Kak)\\s*(?:${PRAY}|${broken})+`, 'giu'), `$1 ${PRAY}`);
  value = value.replace(new RegExp(`(Baarakallahu fiik|Barakallahu fiik)\\s+${broken}`, 'gi'), `$1 ${PRAY}`);
  value = value.replace(new RegExp(`(Aaamiin|Aamiin|Sama-sama ya Kak|Sama-sama Kak)\\s+${broken}`, 'gi'), `$1 ${PRAY}`);
  value = value.replace(new RegExp(`Kak\\s+${broken}(?=\\s*(?:\\n|$))`, 'gi'), `Kak ${PRAY}`);

  const compact = value.replace(/\s+/g, ' ');
  if (compact.length > 90 || compact.includes('*PEMESANAN BERHASIL*')) {
    value = value.replace(new RegExp(`Biar paket (?:langsung|segera) kami proses ya Kak\\s*(?:${PRAY}|${broken})+`, 'giu'), `Biar paket segera kami proses ya Kak ${PRAY}`);
  }

  value = value.replace(new RegExp(`Baik Kak\\s+(?:${PRAY}|${broken})\\s+Sebentar ya`, 'iu'), `Baik Kak ${PRAY} Sebentar ya`);
  value = value.replace(new RegExp(`Aaamiin\\s*(?:${closingEmoji}\\s*)*`, 'iu'), `Aaamiin ${PRAY}`);
  value = value.replace(new RegExp(`Sama-sama ya Kak\\s*(?:${closingEmoji}\\s*)+`, 'iu'), `Sama-sama ya Kak ${PRAY}`);
  value = value.replace(new RegExp(`Sama-sama Kak\\s*(?:${closingEmoji}\\s*)+`, 'iu'), `Sama-sama Kak ${PRAY}`);
  value = value.replace(new RegExp(`Berkah selalu ya Kak\\s*(?:${closingEmoji}\\s*)+`, 'iu'), `Berkah selalu ya Kak ${SMILE}`);
  value = value.replace(new RegExp(`Baarakallahu fiik ya Kak\\s*${PRAY}\\s*Semoga berkah\\s*${SMILE}`, 'iu'), `Baarakallahu fiik ya Kak ${PRAY}`);
  value = value.replace(new RegExp(`(${closingEmoji})(?:\\s*${closingEmoji})+`, 'gu'), '$1');

  return value.trim();
}

function normalizeProfessionalTone(text) {
